using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; using Norge360.Community.Domain.Entities; namespace Norge360.Community.Infrastructure.Persistence.Configurations; public sealed class CommunityCommentReportConfiguration : IEntityTypeConfiguration<CommunityCommentReport>{ public void Configure(EntityTypeBuilder<CommunityCommentReport> b){ b.ToTable("CommunityCommentReports"); b.HasKey(x=>x.Id); b.Property(x=>x.Reason).HasConversion<short>(); b.Property(x=>x.Description).HasMaxLength(1000); b.HasIndex(x=>new{x.CommentId,x.ReporterUserId}).IsUnique().HasFilter("\"IsDeleted\" = false"); b.HasQueryFilter(x=>!x.IsDeleted); }}
